from flask import Flask, request

app = Flask(__name__)

@app.route('/welcome')
def welcome():
    user_name = request.args.get('name', 'Guest')
    return f"<h1>Welcome, <b>{user_name}</b>!</h1>"

if __name__ == '__main__':
    app.run(debug=True)